					.defaultTo(trx.fn.now())
					.notNullable();
				table
					.timestamp('updated_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();

				table.index(['company_id']);
			});

			logger.log('Successfully created github_installations table');
		} else {
			logger.log('github_installations table already exists, skipping');
		}
	});
}

